INSERT INTO public.documents VALUES ('e10b706f-081c-42db-8888-b4dc150d3474', 'Barcalys code of conduct.pdf', 'E:/DS and ML/Jatayu/Gen AI/Projects/Audit/Docs\Barcalys code of conduct.pdf', 'Barclays  Code  of Conduct  
1. Purpose  and Va\ues 
• Integrity:  Act honestly  and transparently  in all dealings.  
• Respect:  Treat colleagues,  customers,  and communities  with dignity.  
• Service:  Put clients''  interests  first and deliver  responsibly.  
• Excellence:  Strive  for high standards  in performance  and innovation.  
• Stewardship:  Safeguard  Barclays''  reputation  and contribute  positively  to society.  
2. Compliance  and Legal  Ob\igations  
• Adhere  to all applicable  laws,  regulations,  and internal  policies.  
• Cooperate  fully with regulators  and auditors.  
• Report  any suspected  breaches  promptly.  
3. Customer  Commitment  
• Protect  customer  data and privacy.  
• Provide  fair, transpa  rent, and responsible  financial  products.  
• Avoid  conflicts  of interest  and disclose them  when they  arise.  
4. Workp \ace Conduct  
• Promote  diversity,  equity,  and inclusion.  
• Maintain  a safe,  respectful,  and harassment -free environment.  
• Encourage  open  communication  and accountability.  
5. Ethical  Business  Practices  
• Reject  bribery,  corruption,  and unethical  inducements.  
• Ensure  responsible  sourcing  and vendor  relationships.  
• Uphold  sustainability  and environmental  responsibility.  
6. Confidentiality  and Data  Protection  
• Safeguard  sensitive  information.  
• Use technology  responsibly  and securely.  • Report  data breaches  immediately.  
7. Accountability  and Reporting  
• Employees  are responsible  for their actions  and decisions.  
• Speak  up culture:  encourage  reporting  of misconduct  without  fear of retaliation.  
• Managers  must lead by example  and enforce  standards  consistently.  ', '{"status": "processed"}', '2026-01-22 07:53:48.195487+00', '2026-01-22 07:53:48.195487+00');
INSERT INTO public.documents VALUES ('1defea47-c1ca-4808-8e8a-49b82ee1ba64', 'Barclays HR Policy Manual (2024).pdf', 'E:/DS and ML/Jatayu/Gen AI/Projects/Audit/Docs\Barclays HR Policy Manual (2024).pdf', 'Barclays HR Policy Manual (2024)   
Table of Contents   
1. Code of Conduct & Ethics Policy  
2. Recruitment & Employment Policy  
3. Compensa Ɵon & Beneﬁts Policy   
4. Performance Management Policy  
